def topo_sort(graph):
    # Build reverse graph: dep -> dependents, plus in-degree (= # unsatisfied deps)
    dependents = defaultdict(list)
    in_degree = {}
    nodes = set(graph.keys())
    for node, deps in graph.items():
        in_degree.setdefault(node, 0)
        for d in deps:
            dependents[d].append(node)
            in_degree[node] = in_degree.get(node, 0) + 1
            nodes.add(d)
            in_degree.setdefault(d, 0)
    # Recompute in_degree cleanly so deps not in graph keys are 0
    in_degree = {n: 0 for n in nodes}
    for node, deps in graph.items():
        in_degree[node] = len(set(deps))
    ready = [n for n in nodes if in_degree[n] == 0]
    heapq.heapify(ready)
    out = []
    while ready:
        n = heapq.heappop(ready)
        out.append(n)
        for m in dependents[n]:
            in_degree[m] -= 1
            if in_degree[m] == 0:
                heapq.heappush(ready, m)
    if len(out) != len(nodes):
        raise ValueError('cycle detected')
    return out

